import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.ResultSet;

public class UserAuth {
    public boolean authenticateUser(String username, String password) {
        boolean isAuthenticated = false;

        // FIXED: Using parameterized queries via PreparedStatement separates SQL logic from data.
        // This prevents the database from interpreting user input as executable SQL code.
        String query = "SELECT * FROM users WHERE username = ? AND password = ?";

        try (Connection conn = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydb", "user", "pass");
             // PreparedStatement pre-compiles the SQL statement, treating inputs strictly as literal values
             PreparedStatement pstmt = conn.prepareStatement(query)) {

            // Safely bind the user input to the parameter placeholders
            pstmt.setString(1, username);
            pstmt.setString(2, password);

            ResultSet rs = pstmt.executeQuery();
            if (rs.next()) {
                isAuthenticated = true;
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
        return isAuthenticated;
    }
}
